2	import { formatTime, playBeep } from '../logic/timer';
3	
4	interface Props {
5	  label: string;
6	  seconds: number;
7	  testId?: string;
8	}
9	
10	export function Timer({ label, seconds, testId }: Props) {
11	  const [remaining, setRemaining] = useState(seconds);
12	  const [running, setRunning] = useState(false);
13	  const [finished, setFinished] = useState(false);
14	  const intervalRef = useRef<number | null>(null);
15	
16	  useEffect(() => {
17	    setRemaining(seconds);
18	    setRunning(false);
19	    setFinished(false);
20	    return () => {
21	      if (intervalRef.current != null) {
22	        window.clearInterval(intervalRef.current);
23	        intervalRef.current = null;
24	      }
25	    };
26	  }, [seconds]);
27	
28	  useEffect(() => {
29	    if (!running) return;
30	    intervalRef.current = window.setInterval(() => {
31	      setRemaining((r) => {
32	        if (r <= 1) {
33	          if (intervalRef.current != null) {
34	            window.clearInterval(intervalRef.current);
35	            intervalRef.current = null;
36	          }
37	          setRunning(false);
38	          setFinished(true);
39	          playBeep();
40	          return 0;
41	        }
42	        return r - 1;
43	      });
44	    }, 1000);
45	    return () => {
46	      if (intervalRef.current != null) {
47	        window.clearInterval(intervalRef.current);
48	        intervalRef.current = null;
49	      }
50	    };
