        <iframe
          src={`https://www.youtube.com/embed/${videoId}?autoplay=1&rel=0${startParam}`}
          allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
          allowFullScreen
          class="h-full w-full"
        />
      </div>
    </div>
  );
}

